```powershell
Configuration GestionServeur {
    Import-DscResource -ModuleName PSDesiredStateConfiguration

    Node 'localhost' {
        # Service Windows
        Service Spooler {
            Name        = 'Spooler'
            State       = 'Running'
            StartupType = 'Automatic'
        }

        # Fichier avec contenu
        File ConfigApp {
            DestinationPath = 'C:\App\config.json'
            Ensure          = 'Present'
            Contents        = '{"port": 3000, "env": "prod"}'
        }

        # Entrée dans le registre
        Registry MaxConnections {
            Key       = 'HKLM:\SYSTEM\CurrentControlSet\Services\Tcpip\Parameters'
            ValueName = 'TcpMaxConnections'
            ValueData = '1000'
            ValueType = 'Dword'
            Ensure    = 'Present'
        }

        # Variables d'environnement
        Environment AppHome {
            Name   = 'APP_HOME'
            Value  = 'C:\App'
            Ensure = 'Present'
        }
    }
}
```

