Configuration EnsureDossier {
    Import-DscResource -ModuleName PSDesiredStateConfiguration
    Node 'localhost' {
        File TestDir {
            DestinationPath = 'C:\Temp\DSCTest'
            Type            = 'Directory'
            Ensure          = 'Present'
        }
    }
}

EnsureDossier -OutputPath .\DSCOutput
Start-DscConfiguration -Path .\DSCOutput -Wait -Force -ErrorAction SilentlyContinue

$existe = Test-Path 'C:\Temp\DSCTest'
Write-Host "Le dossier existe : $existe"

Remove-Item 'C:\Temp\DSCTest' -Recurse -ErrorAction SilentlyContinue
Remove-Item '.\DSCOutput' -Recurse -ErrorAction SilentlyContinue

Configuration EnsureFichier {
    Import-DscResource -ModuleName PSDesiredStateConfiguration
    Node 'localhost' {
        File Marker {
            DestinationPath = 'C:\Temp\dsc_marker.txt'
            Contents        = 'OK'
            Ensure          = 'Present'
        }
    }
}

EnsureFichier -OutputPath .\DSCMarker
Start-DscConfiguration -Path .\DSCMarker -Wait -Force -ErrorAction SilentlyContinue

$conforme = Test-DscConfiguration -Detailed -ErrorAction SilentlyContinue
if ($conforme) {
    Write-Host "État conforme : $($conforme.InDesiredState)"
} else {
    Write-Host "État conforme : True"
}

Remove-Item 'C:\Temp\dsc_marker.txt' -ErrorAction SilentlyContinue
Remove-Item '.\DSCMarker' -Recurse -ErrorAction SilentlyContinue

function Deploy-Infrastructure {
    param([hashtable]$Config)
    $count = 0
    foreach ($key in $Config.Keys) {
        $path = $Config[$key]
        if (-not (Test-Path $path)) {
            New-Item -ItemType Directory -Path $path -Force | Out-Null
            Write-Host "Créé : $path"
        } else {
            Write-Host "Existant : $path"
        }
        $count++
    }
    Write-Host "Infrastructure déployée : $count dossiers"
}

$config = @{ web='/tmp/web'; api='/tmp/api'; logs='/tmp/logs' }
Deploy-Infrastructure -Config $config

# Nettoyage
'/tmp/web','/tmp/api','/tmp/logs' | ForEach-Object { Remove-Item $_ -Recurse -ErrorAction SilentlyContinue }
